// Storage adapter: uses Claude's window.storage when running inside an artifact,
// falls back to localStorage for a normally deployed website.
const storage = {
  async get(key, shared) {
    if (typeof window !== "undefined" && window.storage) {
      return window.storage.get(key, shared);
    }
    const raw = localStorage.getItem(key);
    return raw ? { key, value: raw, shared: !!shared } : null;
  },
  async set(key, value, shared) {
    if (typeof window !== "undefined" && window.storage) {
      return window.storage.set(key, value, shared);
    }
    localStorage.setItem(key, value);
    return { key, value, shared: !!shared };
  },
};

